import React, { useState, useEffect } from 'react';
import { Card, Button, Modal, Form, Row, Col } from 'react-bootstrap';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import { FaShip } from 'react-icons/fa';

const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

function BookingCardView() {
  const [boats, setBoats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [selectedBoat, setSelectedBoat] = useState(null);
  const [formData, setFormData] = useState({
    userName: '',
    seats: '',
    day: '',
    date: '',
    price: '',
  });

  useEffect(() => {
    const fetchBoats = async () => {
      try {
        const response = await fetch('http://127.0.0.1:5000/user_view_boat');
        if (!response.ok) {
          throw new Error('Failed to fetch boats');
        }
        const data = await response.json();
        setBoats(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchBoats();
  }, []);

  const handleShow = (boat) => {
    setSelectedBoat(boat);
    setShowModal(true);
  };

  const handleClose = () => {
    setShowModal(false);
    setFormData({ userName: '', seats: '', day: '', date: '', price: '' });
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleBooking = () => {
    const { userName, seats, day, date, price } = formData;
    if (!userName || !seats || !day || !date || !price) {
      toast.warning('Please fill all booking details.');
      return;
    }

    console.log('Booking Details:', { ...formData, boat: selectedBoat.name });
    toast.success('Booking Confirmed!');
    handleClose();
  };

  if (loading) {
    return (
      <div className="container py-4 text-center">
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
        <p>Loading boats...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container py-4 text-center text-danger">
        <p>Error: {error}</p>
      </div>
    );
  }

  if (boats.length === 0) {
    return (
      <div className="container py-4 text-center">
        <p>No boats available at the moment.</p>
      </div>
    );
  }
  const getImageUrl = (imageName) => {
    if (!imageName) return DefaultBoatImage;
    return `http://localhost:5000/static/upload/${imageName}`; // Update with your backend URL
  };

  return (
    <div className="container py-4">
      <h2 className="text-center mb-4 fw-bold">Available Boats</h2>
      <Row>
        {boats.map((boat, idx) => (
          <Col md={6} key={idx} className="mb-4">
            <Card className="shadow-lg border-0 rounded-4">
              <Card.Img 
                variant="top" 
                src={boat.image || 'default-boat-image.jpg'} 
                className="rounded-top-4" 
                style={{ width: '100%', height: '300px', objectFit: 'cover' }} 
                alt={boat.name}
              />
              <Card.Body>
                <Card.Title className="fw-bold text-primary">
                  <FaShip className="me-2" />
                  {boat.name}
                </Card.Title>
                <Card.Text><strong>Type:</strong> {boat.type}</Card.Text>
                <Card.Text><strong>Description:</strong> {boat.description}</Card.Text>
                <Card.Text><strong>Seats:</strong> {boat.seatCount}</Card.Text>
                <Card.Text><strong>Year Built:</strong> {boat.yearBuilt}</Card.Text>
                <Card.Text><strong>Reg No:</strong> {boat.registerNumber}</Card.Text>
                <Button className="rounded-pill w-100 fw-semibold" variant="primary" onClick={() => handleShow(boat)}>
                  Book Now
                </Button>
              </Card.Body>
            </Card>
          </Col>
        ))}
      </Row>

      <Modal show={showModal} onHide={handleClose} centered>
        <Modal.Header closeButton>
          <Modal.Title>Book {selectedBoat?.name}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <Form>
            <Form.Group className="mb-3">
              <Form.Label>User Name</Form.Label>
              <Form.Control
                type="text"
                name="userName"
                value={formData.userName}
                onChange={handleChange}
                placeholder="Enter your name"
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Number of Seats</Form.Label>
              <Form.Control
                type="number"
                name="seats"
                value={formData.seats}
                onChange={handleChange}
                placeholder="e.g., 2"
                min="1"
                max={selectedBoat?.seatCount}
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Day</Form.Label>
              <div>
                {days.map((day, idx) => (
                  <Form.Check
                    key={idx}
                    inline
                    label={day}
                    name="day"
                    type="radio"
                    value={day}
                    checked={formData.day === day}
                    onChange={handleChange}
                  />
                ))}
              </div>
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Date</Form.Label>
              <Form.Control
                type="date"
                name="date"
                value={formData.date}
                onChange={handleChange}
              />
            </Form.Group>

            <Form.Group className="mb-3">
              <Form.Label>Price (in ₹)</Form.Label>
              <Form.Control
                type="number"
                name="price"
                value={formData.price}
                onChange={handleChange}
                placeholder="e.g., 2000"
              />
            </Form.Group>
          </Form>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="danger" onClick={handleClose}>
            Cancel
          </Button>
          <Button variant="primary" onClick={handleBooking}>
            Confirm Booking
          </Button>
        </Modal.Footer>
      </Modal>
    </div>
  );
}

export default BookingCardView;
